const speciesOf = (id) => SPECIES.find((s) => s.id === id) || SPECIES[SPECIES.length - 1];
const PICS = ["pachira", "monstera", "blades", "zz", "palm", "fern", "trail", "pearls", "pepe", "cone", "sprout"];
const infoOf = (b) => b.custom
  ? { ...b.custom, pic: PICS.includes(b.custom.pic) ? b.custom.pic : "sprout", latin: b.custom.latin || "" }
  : speciesOf(b.speciesId);
const isUnknown = (b) => !b.custom && b.speciesId === "etc";

const NAME_IDEAS = ["초코", "몽이", "김초록", "풀", "여름", "송이", "두부", "용기"];

/* ─── date utils ────────────────────────────────────────────────── */
const pad = (n) => String(n).padStart(2, "0");
const toKey = (d) => `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
const todayKey = () => toKey(new Date());
const fromKey = (k) => { const [y, m, d] = k.split("-").map(Number); return new Date(y, m - 1, d); };
const daysBetween = (a, b) => Math.round((fromKey(b) - fromKey(a)) / 86400000);
const fmtShort = (k) => { const d = fromKey(k); return `${d.getMonth() + 1}월 ${d.getDate()}일`; };
const wa = (s) => { const c = s.charCodeAt(s.length - 1); return c >= 0xac00 && c <= 0xd7a3 && (c - 0xac00) % 28 !== 0 ? "과" : "와"; };

function waterInfo(buddy) {
  const sp = infoOf(buddy);
  const logs = [...buddy.waterLog].sort();
  const last = logs[logs.length - 1] || null;
  const since = last ? daysBetween(last, todayKey()) : null;
  if (!sp.water) return { last, sinceLast: since, dday: null, due: false, noCycle: true };
  if (!last) return { last: null, sinceLast: null, dday: 0, due: true };
  const dday = sp.water - since; // days until next watering
  return { last, sinceLast: since, dday, due: dday <= 0 };
}

/* ─── growth stages ─────────────────────────────────────────────
   단계는 (1) 함께한 날과 (2) 제때 물 준 횟수(돌봄)를 함께 봄.
   돌봄이 메인: 물을 제때 줄수록 다음 단계로. 오래 방치하면 'wilt'(시듦).
   4단계: sprout(새싹) → growing(자람) → lush(무성) → bloom(만개)        */
const STAGES = [
  { key: "sprout",  label: "새싹",   need: 0,  scale: 0.78, leaves: 1 },
  { key: "growing", label: "자라는 중", need: 3,  scale: 0.9,  leaves: 2 },
  { key: "lush",    label: "무성함", need: 7,  scale: 1.0,  leaves: 3 },
  { key: "bloom",   label: "만개",   need: 12, scale: 1.08, leaves: 4 },
];

// 제때 준 물주기 횟수(돌봄 점수). 권장 주기의 1.6배 안에 다음 물을 줬으면 '제때'로 인정.
function careScore(buddy) {
  const sp = infoOf(buddy);
  const cyc = sp.water || 9;
  const logs = [...new Set(buddy.waterLog)].sort();
  if (logs.length <= 1) return logs.length; // 첫 물주기도 1점
  let score = 1;
  for (let i = 1; i < logs.length; i++) {
    const gap = daysBetween(logs[i - 1], logs[i]);
    if (gap > 0 && gap <= cyc * 1.6) score++;
  }
  return score;
}

function growthOf(buddy) {
  const w = waterInfo(buddy);
  const cyc = infoOf(buddy).water || 9;
  const wilting = w.last && w.sinceLast != null && w.sinceLast > cyc * 2.5;
  const score = careScore(buddy);
  let idx = 0;
  for (let i = 0; i < STAGES.length; i++) if (score >= STAGES[i].need) idx = i;
  const cur = STAGES[idx];
  const next = STAGES[idx + 1] || null;
  const prog = next ? Math.min(1, (score - cur.need) / (next.need - cur.need)) : 1;
  return { idx, stage: cur, next, score, prog, wilting, ...w };
}

/* ─── persistence (배포판: 브라우저 localStorage) ───────────────── */
function loadState() {
  try { return JSON.parse(localStorage.getItem("pp-care-state-v3")); } catch (e) { return null; }
}
function saveState(state) {
  try { localStorage.setItem("pp-care-state-v3", JSON.stringify(state)); } catch (e) {}
}

/* ─── Claude API (배포판: /api/chat 프록시 경유, 키는 서버에만) ──── */
async function askClaude({ system, messages, maxTokens = 1000 }) {
  const res = await fetch("/api/chat", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ max_tokens: maxTokens, system, messages }),
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message || "API error");
  return (data.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n").trim();
}

function buddyContext(buddies) {
  if (!buddies.length) return "고객이 아직 버디(식물)를 등록하지 않았습니다.";
  return buddies.map((b) => {
    const sp = infoOf(b);
    const w = waterInfo(b);
    const lastTxt = w.last ? `${w.sinceLast}일 전(${fmtShort(w.last)})` : "기록 없음";
    if (isUnknown(b)) return `- ${b.name} (종 미확인 — 고객이 '기타 버디'로 등록함) · 함께한 첫날 ${fmtShort(b.since)} · 마지막 물주기 ${lastTxt}`;
    return `- ${b.name} (${sp.name}${sp.latin ? ", " + sp.latin : ""}) · 함께한 첫날 ${fmtShort(b.since)} · 권장 물주기 ${sp.water}일 · 마지막 물주기 ${lastTxt} · 빛 ${sp.light} · 적정온도 ${sp.temp} · 메모: ${sp.tip}`;
  }).join("\n");
}

